      {:ok, result} = HtmlToMarkdown.convert("<p>The equation x<sup>3</sup> + y<sup>3</sup> = z<sup>3</sup> has no solutions.</p>", visitor)
      assert String.contains?(to_string(result.content), "The equation x + y = z has no solutions.")
    end
  end

  describe "visitor_underline_custom" do
    test "Visitor replaces underline with custom markup" do
      visitor = %{
      :handle_underline => fn(_ctx, _text) ->
        {:custom, "_{text}_"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>This is <u>very important</u> text.</p>", visitor)
      assert String.contains?(to_string(result.content), "_very important_")
      refute String.contains?(to_string(result.content), "**")
    end
  end

  describe "visitor_underline_skip" do
    test "Visitor skips underline elements from output" do
      visitor = %{
      :handle_underline => fn(_ctx, _text) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>Normal text with <u>underlined part</u> and more text.</p>", visitor)
      assert String.contains?(to_string(result.content), "Normal text with")
      assert String.contains?(to_string(result.content), "and more text.")
      refute String.contains?(to_string(result.content), "underlined part")
    end
  end

  describe "visitor_video_custom" do
    test "Visitor replaces video with custom link" do
      visitor = %{
      :handle_video => fn(_ctx, _src) ->
        {:custom, "[VIDEO: {src}]"}
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<p>Watch our tutorial:</p><video src=\"tutorial.mp4\" width=\"320\" height=\"240\" controls></video><p>Great content!</p>", visitor)
      assert String.contains?(to_string(result.content), "[VIDEO: tutorial.mp4]")
      assert String.contains?(to_string(result.content), "Watch our tutorial:")
      assert String.contains?(to_string(result.content), "Great content!")
    end
  end

  describe "visitor_video_skip" do
    test "Visitor removes video elements entirely" do
      visitor = %{
      :handle_video => fn(_ctx, _src) ->
        :skip
      end,
    }

      {:ok, result} = HtmlToMarkdown.convert("<h2>Demo</h2><video src=\"demo.webm\"></video><p>See the demo above.</p>", visitor)
      assert String.contains?(to_string(result.content), "Demo")
      assert String.contains?(to_string(result.content), "See the demo above.")
      refute String.contains?(to_string(result.content), "demo.webm")
    end
  end
end
